   1 | <!DOCTYPE html>
   2 | <html lang="zh-Hant">
   3 | <head>
   4 |     <meta charset="UTF-8">
   5 |     <meta name="viewport" content="width=device-width, initial-scale=1.0">
   6 |     <title>VCC PRE 廣播主控室操作員矩陣首頁系統 v0.5</title>
   7 |     <style>
   8 |         body {
   9 |             margin: 0;
  10 |             padding: 0;
  11 |             background-color: #090d16;
  12 |             font-family: "Microsoft JhengHei", "微軟正黑體", Arial, sans-serif;
  13 |         }
  14 | 
  15 |         /* 獨立沙盒包裝層 */
  16 |         .vcc-pre-system-sandbox-wrapper {
  17 |             --sidebar-width: 260px;
  18 |             --primary-color: #38bdf8;
  19 |             --bg-dark: #090d16;
  20 |             --bg-panel: #111827;
  21 |             --success: #10b981;
  22 |             --warning: #f59e0b;
  23 |             --danger: #ef4444;
  24 |             --on-air: #22c55e;
  25 | 
  26 |             display: flex !important;
  27 |             width: 100% !important;
  28 |             height: 100vh !important;
  29 |             min-height: 780px;
  30 |             background-color: var(--bg-dark);
  31 |             color: #f1f5f9;
  32 |             box-sizing: border-box;
  33 |             overflow: hidden !important;
  34 |             position: relative;
  35 |         }
  36 | 
  37 |         .vcc-pre-system-sandbox-wrapper *,
  38 |         .vcc-pre-system-sandbox-wrapper *:before,
  39 |         .vcc-pre-system-sandbox-wrapper *:after {
  40 |             box-sizing: border-box;
  41 |         }
  42 | 
  43 |         /* 左側常駐工作列 */
  44 |         .sidebar {
  45 |             width: var(--sidebar-width);
  46 |             min-width: var(--sidebar-width);
  47 |             background-color: var(--bg-panel);
  48 |             border-right: 1px solid #1f2937;
  49 |             display: flex;
  50 |             flex-direction: column;
  51 |             justify-content: space-between;
  52 |             height: 100%;
  53 |             z-index: 10;
  54 |         }
  55 |         .sidebar-header {
  56 |             padding: 24px 20px;
  57 |             text-align: center;
  58 |             font-size: 16px;
  59 |             font-weight: bold;
  60 |             letter-spacing: 1px;
  61 |             color: var(--primary-color);
  62 |             border-bottom: 1px solid #1f2937;
  63 |             background: linear-gradient(180deg, rgba(56,189,248,0.05) 0%, rgba(0,0,0,0) 100%);
  64 |         }
  65 |         .sidebar-menu { flex: 1; padding: 20px 0; }
  66 |         .menu-item {
  67 |             padding: 15px 20px; color: #9ca3af; cursor: pointer; font-size: 14px; display: flex; align-items: center; gap: 12px; transition: all 0.2s;
  68 |         }
  69 |         .menu-item:hover { background-color: rgba(56, 189, 248, 0.04); color: #fff; }
  70 |         .menu-item.active {
  71 |             background-color: rgba(56, 189, 248, 0.08); color: var(--primary-color); border-left: 4px solid var(--primary-color); font-weight: bold;
  72 |         }
  73 |         .sidebar-footer { padding: 20px; font-size: 11px; color: #4b5563; text-align: center; border-top: 1px solid #1f2937; line-height: 1.6; }
  74 | 
  75 |         /* 右側核心工作區 */
  76 |         .main-content { flex: 1; padding: 25px; overflow-y: auto !important; height: 100%; background-color: var(--bg-dark); }
  77 |         .page { display: none; }
  78 |         .page.active { display: block; }
  79 | 
  80 |         /* 模組容器 */
  81 |         .panel-box {
  82 |             background-color: var(--bg-panel); padding: 22px; border-radius: 8px; box-shadow: 0 10px 25px -5px rgba(0, 0, 0, 0.7); margin-bottom: 20px; border: 1px solid #1f2937;
  83 |         }
  84 |         .panel-header-box {
  85 |             display: flex; justify-content: space-between; align-items: center; margin-bottom: 18px; border-bottom: 1px solid #1f2937; padding-bottom: 10px;
  86 |         }
  87 |         .panel-title { font-size: 14px; color: var(--primary-color); font-weight: bold; letter-spacing: 0.5px; text-transform: uppercase; }
  88 | 
  89 |         /* 廣播主控專用：頂部極致三欄網格佈局 (首頁專用) */
  90 |         .mcr-operator-grid {
  91 |             display: grid;
  92 |             grid-template-columns: 1.2fr 1fr;
  93 |             gap: 20px;
  94 |             margin-bottom: 20px;
  95 |         }
  96 |         @media(max-width: 1200px) { .mcr-operator-grid { grid-template-columns: 1fr; } }
  97 | 
  98 |         /* MCR On-Air 監測監視器樣式 */
  99 |         .mcr-monitor-card {
 100 |             background: linear-gradient(135deg, #0b1519 0%, #111827 100%);
 101 |             border: 2px solid #10b981;
 102 |             border-radius: 8px;
 103 |             padding: 20px;
 104 |             position: relative;
 105 |             box-shadow: 0 0 20px rgba(16, 185, 129, 0.1);
 106 |         }
 107 |         .mcr-monitor-card.no-active {
 108 |             border-color: #374151;
 109 |             box-shadow: none;
 110 |         }
 111 |         .mcr-tag-live {
 112 |             position: absolute; top: 15px; right: 20px; background-color: var(--on-air); color: #fff; padding: 3px 8px; font-size: 11px; font-weight: bold; border-radius: 4px; letter-spacing: 1px; animation: blinker 1.5s linear infinite;
 113 |         }
 114 |         @keyframes blinker { 50% { opacity: 0.3; } }
 115 | 
 116 |         .mcr-label-sub { font-size: 12px; color: #9ca3af; text-transform: uppercase; margin-bottom: 4px; font-weight: 600; }
 117 |         .mcr-prog-title { font-size: 26px; font-weight: 900; color: #ffffff; margin: 5px 0 15px 0; letter-spacing: 0.5px; text-shadow: 0 2px 4px rgba(0,0,0,0.5); }
 118 |         .mcr-prog-countdown { font-family: 'Courier New', Courier, monospace; font-size: 24px; color: var(--warning); font-weight: bold; }
 119 |         .mcr-next-bar { background-color: rgba(255,255,255,0.03); border-left: 3px solid var(--primary-color); padding: 10px 15px; margin-top: 15px; border-radius: 0 4px 4px 0; }
 120 | 
 121 |         /* Traffic 摘要狀態卡片 */
 122 |         .traffic-summary-card {
 123 |             background: #111827; border: 1px solid #1f2937; border-radius: 8px; padding: 20px; display: grid; grid-template-columns: 1fr 1fr; gap: 15px;
 124 |         }
 125 |         .traffic-stat-block {
 126 |             background: #0b0f19; padding: 12px; border-radius: 6px; border-top: 3px solid #4b5563; text-align: center;
 127 |         }
 128 |         .traffic-stat-block.alert-active { border-top-color: var(--danger); background: rgba(239, 68, 68, 0.03); }
 129 |         .traffic-stat-num { font-family: monospace; font-size: 24px; font-weight: bold; color: #fff; margin-top: 4px; }
 130 | 
 131 |         /* 雙欄排版（用於行事曆與表單對齊） */
 132 |         .grid-layout-2col { display: grid; grid-template-columns: 340px 1fr; gap: 20px; margin-bottom: 20px; }
 133 |         @media(max-width: 1024px) { .grid-layout-2col { grid-template-columns: 1fr; } }
 134 | 
 135 |         /* --- NATIVE GUI CALENDAR STYLE --- */
 136 |         .gui-calendar-card { background: #090d16; border: 1px solid #1f2937; border-radius: 6px; padding: 12px; }
 137 |         .calendar-nav-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 10px; }
 138 |         .calendar-nav-header span { font-size: 14px; font-weight: bold; color: #fff; }
 139 |         .calendar-nav-btn { background: #1f2937; color: #fff; padding: 4px 8px; font-size: 12px; border-radius: 4px; cursor: pointer; }
 140 |         .calendar-nav-btn:hover { background: var(--primary-color); color: #090d16; }
 141 |         .calendar-grid-head { display: grid; grid-template-columns: repeat(7, 1fr); text-align: center; font-size: 11px; color: #4b5563; margin-bottom: 6px; font-weight: bold; }
 142 |         .calendar-grid-body { display: grid; grid-template-columns: repeat(7, 1fr); gap: 4px; text-align: center; }
 143 |         .calendar-day-cell {
 144 |             aspect-ratio: 1; background: #111827; border-radius: 6px; display: flex; flex-direction: column; justify-content: center; align-items: center; font-size: 13px; font-family: monospace; cursor: pointer; position: relative; transition: all 0.15s; border: 1px solid transparent; color: #cbd5e1; gap:1px;
 145 |         }
 146 |         .calendar-day-cell:hover { border-color: var(--primary-color); background: rgba(56, 189, 248, 0.06); }
 147 |         .calendar-day-cell.empty { background: transparent; cursor: default; border: none; }
 148 |         .calendar-day-cell.selected { background: var(--primary-color) !important; color: #090d16 !important; font-weight: bold; border-color: var(--primary-color) !important; }
 149 |         .calendar-day-cell.today { border: 1px solid var(--success); }
 150 |         .calendar-day-cell.selected.today { border-color: var(--primary-color) !important; }
 151 |         .calendar-prog-count { font-size:9px; color:#64748b; font-weight:normal; font-family:sans-serif; }
 152 |         .calendar-day-cell.selected .calendar-prog-count { color:#090d16; opacity:0.7; }
 153 |         .calendar-day-cell.has-progs { border-bottom:2px solid #a855f7; }
 154 | 
 155 |         /* 表單與控制元件 */
 156 |         .input-form { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
 157 |         .input-group { display: flex; flex-direction: column; }
 158 |         .input-group.full-width { grid-column: span 2; }
 159 |         .input-group label { font-size: 12px; color: #9ca3af; margin-bottom: 4px; }
 160 |         .input-group input, .input-group select, .input-group textarea {
 161 |             background-color: #090d16; border: 1px solid #374151; color: #fff; padding: 8px 10px; border-radius: 4px; font-size: 13px; outline: none;
 162 |         }
 163 |         .input-group input:focus, .input-group select:focus, .input-group textarea:focus { border-color: var(--primary-color); }
 164 |         /* 窄螢幕響應式: 768px 以下調整表單成單欄 */
 165 |         @media (max-width: 768px) {
 166 |             .input-form { grid-template-columns: 1fr; }
 167 |             .input-form .input-group input[type="text"] { font-size: 16px; padding: 10px 8px; }
 168 |             .input-group.full-width { grid-column: span 1; }
 169 |         }
 170 | 
 171 |         /* 頂部全局控制列 */
 172 |         .global-filter-bar {
 173 |             background: #111827; padding: 12px 20px; border-radius: 6px; margin-bottom: 20px; display: flex; align-items: center; gap: 15px; border: 1px solid #1f2937;
 174 |         }
 175 |         .global-filter-bar input[type="date"] { background: #090d16; border: 1px solid #374151; color: #fff; padding: 6px 10px; border-radius: 4px; }
 176 | 
 177 |         /* 按鈕樣式 */
 178 |         .btn-zone { display: flex; gap: 10px; margin-top: 10px; }
 179 |         button { padding: 9px 14px; font-size: 12px; font-weight: bold; border-radius: 4px; cursor: pointer; border: none; transition: all 0.2s; }
 180 |         .btn-add { background-color: #0284c7; color: white; }
 181 |         .btn-update { background-color: var(--warning); color: #090d16; }
 182 |         .btn-start { background-color: var(--success); color: white; font-size: 13px; padding: 10px 20px; box-shadow: 0 0 10px rgba(16,185,129,0.2); }
 183 |         .btn-sync { background-color: #374151; color: white; }
 184 |         .btn-cancel { background-color: #4b5563; color: white; }
 185 |         .btn-danger-action { background-color: rgba(239, 68, 68, 0.15); color: #f87171; border: 1px solid var(--danger); }
 186 | 
 187 |         .btn-ctrl-group { display: flex; gap: 6px; }
 188 |         .btn-ctrl { padding: 6px 12px; font-size: 11px; font-weight: bold; border-radius: 4px; color: white; }
 189 |         .btn-import-ui { background-color: #374151; }
 190 |         .btn-export-ui { background-color: #0284c7; }
 191 |         .btn-clear-ui { background-color: rgba(239, 68, 68, 0.15); color: #f87171; border: 1px solid #dc2626; }
 192 | 
 193 |         /* HUD 全域看板 */
 194 |         .status-panel {
 195 |             background-color: var(--bg-panel); padding: 15px 20px; border-radius: 8px; margin-bottom: 20px; display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; border-left: 5px solid var(--primary-color); border-top: 1px solid #1f2937; border-right: 1px solid #1f2937; border-bottom: 1px solid #1f2937;
 196 |         }
 197 |         .status-item { font-size: 14px; margin: 2px 0; color: #9ca3af; }
 198 |         .status-item span { font-weight: bold; color: var(--warning); }
 199 |         .sync-badge { padding: 3px 7px; border-radius: 4px; font-size: 11px; font-weight: bold; display: inline-block; }
 200 |         .sync-success { background-color: rgba(16, 185, 129, 0.15); color: #34d399; border: 1px solid var(--success); }
 201 |         .sync-loading { background-color: rgba(59, 130, 246, 0.15); color: #60a5fa; border: 1px solid #3b82f6; }
 202 |         #clock { font-family: 'Courier New', Courier, monospace; font-size: 48px; color: var(--success); font-weight: bold; text-shadow: 0 0 16px rgba(16, 185, 129, 0.35); letter-spacing: 2px; }
 203 | 
 204 |         /* 系統表格 */
 205 |         .vcc-pre-table { width: 100%; border-collapse: collapse; font-size: 13px; background-color: var(--bg-panel); border-radius: 6px; overflow: hidden; }
 206 |         .vcc-pre-table th { background-color: #090d16; color: #9ca3af; text-align: left; padding: 12px 14px; border-bottom: 2px solid #1f2937; text-transform: uppercase; font-size: 12px; letter-spacing: 0.5px; }
 207 |         .vcc-pre-table td { padding: 12px 14px; border-bottom: 1px solid #1f2937; color: #e5e7eb; }
 208 |         .status-badge { padding: 2px 6px; border-radius: 4px; font-size: 11px; font-weight: bold; }
 209 |         .badge-sched { background-color: #1f2937; color: #cbd5e1; }
 210 |         .badge-periodic { background-color: rgba(168, 85, 247, 0.15); color: #c084fc; border: 1px solid #a855f7; }
 211 | 
 212 |         .btn-action { padding: 4px 8px; font-size: 11px; margin-right: 4px; border-radius: 4px; cursor: pointer; color: white; border: none;}
 213 |         .btn-action-edit { background-color: #d97706; }
 214 |         .btn-action-copy { background-color: #0891b2; }
 215 |         .btn-action-del { background-color: #dc2626; }
 216 | 
 217 |         /* 動態聚焦行 */
 218 |         .row-imminent { color: var(--danger) !important; background-color: rgba(239, 68, 68, 0.1) !important; font-weight: bold; border-left: 5px solid var(--danger) !important; }
 219 |         .row-imminent td { color: var(--danger) !important; }
 220 |         .row-future { color: var(--warning) !important; }
 221 |         .row-future td { color: var(--warning) !important; }
 222 |         .row-dimmed { color: #64748b !important; }
 223 |         .row-dimmed td { color: #64748b !important; }
 224 |         .row-trigger-active { background-color: var(--danger) !important; color: #ffffff !important; font-weight: bold; animation: pulse 0.4s infinite alternate; }
 225 |         .row-trigger-active td { color: #ffffff !important; }
 226 |         @keyframes pulse { 0% { background-color: var(--danger); } 100% { background-color: #b91c1c; } }
 227 |         /* 矩陣捲動容器 */
 228 |         .matrix-scroll-wrap { overflow-y: auto; border: 1px solid #1f2937; border-radius: 6px; }
 229 |         .matrix-scroll-wrap::-webkit-scrollbar { width: 6px; }
 230 |         .matrix-scroll-wrap::-webkit-scrollbar-track { background: #090d16; }
 231 |         .matrix-scroll-wrap::-webkit-scrollbar-thumb { background: #374151; border-radius: 3px; }
 232 | 
 233 |         /* 除錯終端 */
 234 |         .console-terminal {
 235 |             background-color: #030712; border: 1px solid #1f2937; font-family: 'Courier New', Courier, monospace; font-size: 12px; color: #34d399; padding: 12px; border-radius: 6px; height: 130px; overflow-y: auto; line-height: 1.4; margin-top: 5px;
 236 |         }
 237 |         .console-line { margin-bottom: 4px; }
 238 |         .console-time { color: #4b5563; margin-right: 8px; }
 239 | 
 240 |         /* Timeline GUI 時間軸 */
 241 |         .timeline-panel { display:flex; gap:8px; padding:8px 12px; background:#111827; border:1px solid #1f2937; border-radius:6px; margin-bottom:12px; align-items:stretch; }
 242 |         .timeline-label { font-size:11px; color:#64748b; white-space:nowrap; font-family:monospace; min-width:90px; padding-top:20px; }
 243 |         .timeline-tracks-wrap { flex:1; position:relative; overflow-x:hidden; background:#090d16; border-radius:4px; min-height:0; }
 244 |         .timeline-track { display:flex; align-items:center; height:28px; border-bottom:1px solid rgba(31,41,55,0.4); position:relative; }
 245 |         .timeline-track:last-child { border-bottom:none; }
 246 |         .timeline-track-label { width:100px; min-width:100px; font-size:10px; color:#9ca3af; padding:0 6px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; position:relative; z-index:2; }
 247 |         .timeline-track-bar { flex:1; position:relative; height:100%; }
 248 |         .timeline-prog-block { position:absolute; top:3px; height:20px; border-radius:3px; opacity:0.55; cursor:pointer; z-index:3; border:1px solid rgba(255,255,255,0.08); transition:opacity 0.15s; }
 249 |         .timeline-prog-block:hover { opacity:0.85; }
 250 |         .timeline-cue-tick { position:absolute; top:3px; width:2px; height:20px; border-radius:1px; opacity:0.6; cursor:pointer; z-index:4; }
 251 |         .timeline-cue-tick:hover { opacity:1; transform:scaleX(2); z-index:5; }
 252 |         .timeline-now-marker { position:absolute; top:0; width:3px; height:100%; background:var(--danger); z-index:10; border-radius:1px; box-shadow:0 0 8px var(--danger); transition:left 0.4s linear; pointer-events:none; }
 253 |         .timeline-now-label { position:absolute; top:-18px; font-size:10px; font-weight:bold; color:var(--danger); transform:translateX(-50%); white-space:nowrap; z-index:11; pointer-events:none; }
 254 |         .timeline-ruler { display:flex; height:18px; border-bottom:1px solid #1f2937; position:relative; }
 255 |         .timeline-ruler-label { position:absolute; font-size:9px; color:#4b5563; transform:translateX(-50%); top:2px; }
 256 | 
 257 |         /* Week at a Glance */
 258 |         .week-grid { display:grid; grid-template-columns:repeat(7,1fr); gap:1px; background:#1f2937; border-radius:6px; overflow:hidden; }
 259 |         .week-day-header { background:#111827; padding:8px 4px; text-align:center; font-size:11px; color:#9ca3af; font-weight:bold; border-bottom:2px solid #1f2937; }
 260 |         .week-day-header span { display:block; font-size:18px; color:#fff; font-weight:bold; margin-top:2px; }
 261 |         .week-day-header.today { color:#10b981; } .week-day-header.today span { color:#10b981; }
 262 |         .week-day-cell { background:#090d16; padding:4px; min-height:60px; font-size:10px; vertical-align:top; }
 263 |         .week-prog-block { padding:3px 4px; margin-bottom:2px; border-radius:3px; border-left:3px solid; cursor:pointer; line-height:1.3; }
 264 |         .week-prog-block:hover { filter:brightness(1.3); }
 265 |         #rundownTableBody tr { cursor:pointer; }
 266 |         #rundownTableBody tr:hover { background:rgba(56,189,248,0.03); }
 267 |         .week-prog-block .wp-time { color:#94a3b8; font-family:monospace; font-size:9px; }
 268 |         .week-prog-block .wp-name { color:#e2e8f0; font-weight:bold; font-size:10px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }
 269 |         .week-prog-block .wp-tags { display:flex; gap:2px; flex-wrap:wrap; margin-top:1px; }
 270 | 
 271 |         /* Tag & Color Label */
 272 |         .tag-badge { display:inline-block; padding:1px 5px; border-radius:3px; font-size:9px; font-weight:bold; margin:1px 2px 1px 0; }
 273 | 
 274 |         .clr-picker { display:flex; gap:4px; flex-wrap:wrap; margin-top:4px; }
 275 |         .clr-opt { width:24px; height:24px; border-radius:50%; cursor:pointer; border:2px solid transparent; transition:all 0.15s; }
 276 |         .clr-opt:hover { transform:scale(1.2); }
 277 |         .clr-opt.active { border-color:#fff !important; box-shadow:0 0 6px rgba(255,255,255,0.4); }
 278 |         .tag-input-area { display:flex; gap:4px; flex-wrap:wrap; align-items:center; }
 279 |         .tag-input-area input { flex:1; background:#090d16; border:1px solid #374151; color:#fff; padding:5px 8px; border-radius:4px; font-size:12px; outline:none; }
 280 |         .tag-input-area input:focus { border-color:#38bdf8; }
 281 |         .tag-list { display:flex; gap:3px; flex-wrap:wrap; margin-top:4px; }
 282 | 
 283 |         /* 節目 Color Code */
 284 |         .prog-color-0 { --prog-color: #ef4444; } .prog-color-1 { --prog-color: #f59e0b; }
 285 |         .prog-color-2 { --prog-color: #10b981; } .prog-color-3 { --prog-color: #3b82f6; }
 286 |         .prog-color-4 { --prog-color: #8b5cf6; } .prog-color-5 { --prog-color: #ec4899; }
 287 |         .prog-color-6 { --prog-color: #06b6d4; } .prog-color-7 { --prog-color: #f97316; }
 288 |         .prog-color-dot { display:inline-block; width:10px; height:10px; border-radius:50%; margin-right:6px; vertical-align:middle; }
 289 |         .row-onair { background-color: rgba(239,68,68,0.12) !important; border-left:4px solid var(--danger) !important; animation: pulseOnAir 0.6s infinite alternate; }
 290 |         .row-nextup { background-color: rgba(245,158,11,0.08) !important; border-left:4px solid #f59e0b !important; }
 291 |         @keyframes pulseOnAir { 0% { background-color: rgba(239,68,68,0.08); } 100% { background-color: rgba(239,68,68,0.18); } }
 292 |         .matrix-row { border-left: 3px solid var(--prog-color, #374151); } /* 放在高亮 class 之後，不蓋過 .row-imminent/.row-trigger-active 的 border-left */
 293 | 
 294 |         /* Preset 節點表格樣式 */
 295 |         #presetNodesTable { width:100%; border-collapse:collapse; margin-bottom:8px; }
 296 |         #presetNodesTable th { color:#9ca3af; font-size:12px; padding:6px 4px; border-bottom:1px solid #374151; font-weight:600; text-align:left; }
 297 |         #presetNodesTable td { padding:3px 4px; border-bottom:1px solid #1f2937; }
 298 |         #presetNodesTable select,
 299 |         #presetNodesTable input {
 300 |             background-color: #090d16; border: 1px solid #374151; color: #fff;
 301 |             padding: 5px 6px; border-radius: 3px; font-size: 12px; outline: none; width:100%;
 302 |         }
 303 |         #presetNodesTable select:focus,
