3246 |     function playBroadcastBeep(customFreq, presetObj) {
3247 |         if (customFreq === 0 || (presetObj && presetObj.id === "silent")) return;
3248 |         try {
3249 |             const actx = window.audioCtx || new (window.AudioContext || window.webkitAudioContext)();
3250 |             if (actx.state === 'suspended') actx.resume();
3251 |             window.audioCtx = actx;
3252 | 
3253 |             // 如果傳入 soundPreset 物件，使用完整設定（含重複次數、波形）
3254 |             if (presetObj) {
3255 |                 const repeats = presetObj.repeats || 1;
3256 |                 const gap = presetObj.gap || 0;
3257 |                 const dur = presetObj.dur || 0.3;
3258 |                 const freq = presetObj.freq || customFreq || 1000;
3259 |                 let type = presetObj.type || 'sine';
3260 |                 for (let r = 0; r < repeats; r++) {
3261 |                     (function(idx) {
3262 |                         const offset = (dur + gap) * idx;
3263 |                         setTimeout(function() {
3264 |                             const osc = actx.createOscillator();
3265 |                             const gain = actx.createGain();
3266 |                             osc.connect(gain); gain.connect(actx.destination);
3267 |                             osc.type = type;
3268 |                             osc.frequency.value = freq;
3269 |                             gain.gain.setValueAtTime(0.3, actx.currentTime);
3270 |                             osc.start(); osc.stop(actx.currentTime + dur);
3271 |                         }, offset * 1000);
3272 |                     })(r);
3273 |                 }
3274 |                 return;
3275 |             }
3276 | 
3277 |             // 向後相容：只傳頻率數字
3278 |             const freq = customFreq || parseFloat(document.getElementById('cfgBeepFreq').value) || 1500;
3279 |             const duration = parseFloat(document.getElementById('cfgBeepDur').value) || 0.5;
3280 |             const osc = actx.createOscillator(); const gain = actx.createGain();
3281 |             osc.connect(gain); gain.connect(actx.destination);
3282 |             osc.type = 'sine'; osc.frequency.value = freq; gain.gain.setValueAtTime(0.3, actx.currentTime);
3283 |             osc.start(); osc.stop(actx.currentTime + duration);
3284 |         } catch (e) {}
3285 |     }
